export class QuoteDetailComponent {
  // 添加页面离开提醒
  canDeactivate() {
    if (this.hasUnsavedChanges) {
      return confirm('您有未上传的文件，确定要离开吗？未保存的文件将会丢失。');
    }
    return true;
  }
  constructor(route, quoteService, authService, userService, permissionService, tokenService, ngZone) {
    this.route = route;
    this.quoteService = quoteService;
    this.authService = authService;
    this.userService = userService;
    this.permissionService = permissionService;
    this.tokenService = tokenService;
    this.ngZone = ngZone;
    this.quote = null;
    this.loading = true;
    this.error = '';
    this.quoters = [];
    this.suppliers = [];
    this.editMode = false;
    this.quoteForm = {};
    this.uploading = false;
    this.uploadProgress = 0;
    this.assigning = false;
    this.selectedSupplierId = '';
    this.selectedFiles = [];
    this.hasUnsavedChanges = false; // 标记是否有未保存的文件更改
    this.tempCustomerFiles = []; // 临时存储客户文件
    this.tempSupplierFiles = []; // 临时存储供应商文件
    this.tempQuoterFiles = []; // 临时存储报价员文件
    // 临时文件映射，用于FileUtils
    this.tempFilesMap = {
      customer: [],
      supplier: [],
      quoter: []
    };
  }
  ngOnInit() {
    const quoteId = this.route.snapshot.paramMap.get('id');
    if (quoteId) {
      this.loadQuote(quoteId);
      if (this.authService.hasRole('admin')) {
        this.loadQuoters();
      }
      if (this.authService.hasRole('quoter') || this.authService.hasRole('admin')) {
        this.loadSuppliers();
      }
    }
  }
  loadQuote(id) {
    this.loading = true;
    this.quoteService.getQuoteById(id).subscribe({
      next: quote => {
        this.quote = quote;
        this.quoteForm = {
          ...quote
        };
        this.loading = false;
      },
      error: () => {
        this.error = '加载询价单失败';
        this.loading = false;
      }
    });
  }
  loadQuoters() {
    this.userService.getAllUsers().subscribe({
      next: users => {
        this.quoters = users.filter(user => user.role === 'quoter' && user.isActive);
      },
      error: error => {
        console.error('加载报价员失败:', error);
      }
    });
  }
  loadSuppliers() {
    this.userService.getSuppliers().subscribe({
      next: suppliers => {
        this.suppliers = suppliers;
      },
      error: error => {
        console.error('加载供应商列表失败:', error);
      }
    });
  }
  // 获取指定类型的文件列表（包括临时文件）
  getFiles(fileType) {
    if (!this.quote) return [];
    // 更新临时文件映射
    this.updateTempFilesMap();
    return FileUtils.getFilesByType(this.quote, fileType, this.tempFilesMap);
  }
  // 获取指定类型的临时文件
  getTempFilesByType(fileType) {
    this.updateTempFilesMap();
    return FileUtils.getTempFilesByType(this.tempFilesMap, fileType);
  }
  // 检查是否有指定类型的文件
  hasFiles(fileType) {
    if (!this.quote) return false;
    this.updateTempFilesMap();
    return FileUtils.hasFilesByType(this.quote, fileType, this.tempFilesMap);
  }
  // 更新临时文件映射
  updateTempFilesMap() {
    this.tempFilesMap = {
      customer: this.tempCustomerFiles.map(file => FileUtils.createTempFile(file)),
      supplier: this.tempSupplierFiles.map(file => FileUtils.createTempFile(file)),
      quoter: this.tempQuoterFiles.map(file => FileUtils.createTempFile(file))
    };
  }
  downloadFile(fileType, fileIndex) {
    if (!this.quote || this.uploading) return;
    // 根据用户角色和询价单状态决定下载哪个文件
    const user = this.authService.getCurrentUser();
    if (!user) return;
    let actualFileType = fileType;
    if (user.role === 'customer') {
      // 客户：未报价时下载原文件，已报价时下载报价文件
      actualFileType = this.quote.status === 'quoted' ? 'quoter' : 'customer';
    }
    this.quoteService.downloadFile(this.quote._id, actualFileType, fileIndex).subscribe({
      next: blob => {
        this.ngZone.run(() => {
          try {
            const url = window.URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.style.display = 'none';
            document.body.appendChild(a);
            // 获取文件名
            const files = this.getFiles(actualFileType);
            const targetFile = fileIndex !== undefined && files[fileIndex] ? files[fileIndex] : files[0];
            const originalName = targetFile?.originalName || `${this.quote?.quoteNumber}_${actualFileType}.xlsx`;
            a.download = originalName;
            // 使用setTimeout确保DOM操作完成
            setTimeout(() => {
              a.click();
              // 延迟清理URL和DOM元素
              setTimeout(() => {
                document.body.removeChild(a);
                window.URL.revokeObjectURL(url);
              }, 100);
            }, 0);
          } catch (error) {
            console.error('下载文件处理失败:', error);
            alert('下载文件处理失败');
          }
        });
      },
      error: error => {
        this.ngZone.run(() => {
          console.error('下载文件失败:', error);
          alert('下载文件失败');
        });
      }
    });
  }
  // 批量下载文件
  downloadFilesBatch(fileType) {
    if (!this.quote || this.uploading) return;
    // 根据用户角色和询价单状态决定下载哪个文件
    const user = this.authService.getCurrentUser();
    if (!user) return;
    let actualFileType = fileType;
    if (user.role === 'customer') {
      // 客户：未报价时下载原文件，已报价时下载报价文件
      actualFileType = this.quote.status === 'quoted' ? 'quoter' : 'customer';
    }
    this.quoteService.downloadFilesBatch(this.quote._id, actualFileType).subscribe({
      next: blob => {
        this.ngZone.run(() => {
          try {
            const url = window.URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.style.display = 'none';
            document.body.appendChild(a);
            // 生成ZIP文件名（使用英文避免字符编码问题）
            const zipFileName = `${this.quote?.quoteNumber}_${actualFileType}_files.zip`;
            a.download = zipFileName;
            // 使用setTimeout确保DOM操作完成
            setTimeout(() => {
              a.click();
              // 延迟清理URL和DOM元素
              setTimeout(() => {
                document.body.removeChild(a);
                window.URL.revokeObjectURL(url);
              }, 100);
            }, 0);
          } catch (error) {
            console.error('批量下载文件处理失败:', error);
            alert('批量下载文件处理失败');
          }
        });
      },
      error: error => {
        this.ngZone.run(() => {
          console.error('批量下载文件失败:', error);
          alert('批量下载文件失败');
        });
      }
    });
  }
  // 获取文件类型的中文名称
  getFileTypeName(fileType) {
    switch (fileType) {
      case 'customer':
        return '客户询价';
      case 'supplier':
        return '供应商报价';
      case 'quoter':
        return '最终报价';
      default:
        return '文件';
    }
  }
  onFilesSelected(event) {
    const files = Array.from(event.target.files);
    if (files.length === 0) return;
    // 检查用户权限和状态
    const user = this.authService.getCurrentUser();
    if (user?.role === 'customer' && this.quote?.status !== 'pending') {
      alert('询价单不是待处理状态，无法选择文件');
      event.target.value = '';
      return;
    }
    if (user?.role === 'supplier' && !['in_progress', 'rejected'].includes(this.quote?.status || '')) {
      alert('询价单不是处理中或被拒绝状态，无法选择文件');
      event.target.value = '';
      return;
    }
    if ((user?.role === 'quoter' || user?.role === 'admin') && !['pending', 'supplier_quoted', 'in_progress'].includes(this.quote?.status || '')) {
      alert('询价单当前状态不允许上传最终报价文件');
      event.target.value = '';
      return;
    }
    // 检查所有文件类型和大小
    const validFiles = [];
    for (const file of files) {
      // 检查文件类型
      if (!file.name.endsWith('.xlsx') && !file.name.endsWith('.xls')) {
        alert(`文件 "${file.name}" 不是Excel文件，请选择 .xlsx 或 .xls 文件`);
        continue;
      }
      // 检查文件大小 (10MB限制)
      if (file.size > 10 * 1024 * 1024) {
        alert(`文件 "${file.name}" 大小超过10MB限制`);
        continue;
      }
      validFiles.push(file);
    }
    // 根据用户角色将文件分类存储
    if (validFiles.length > 0) {
      this.ngZone.run(() => {
        this.hasUnsavedChanges = true;
        switch (user?.role) {
          case 'customer':
            this.tempCustomerFiles = [...this.tempCustomerFiles, ...validFiles];
            break;
          case 'supplier':
            this.tempSupplierFiles = [...this.tempSupplierFiles, ...validFiles];
            break;
          case 'quoter':
          case 'admin':
            this.tempQuoterFiles = [...this.tempQuoterFiles, ...validFiles];
            break;
        }
      });
    }
    // 清空文件输入框，允许重复选择相同文件
    event.target.value = '';
  }
  // 验证token是否有效
  validateTokenBeforeUpload() {
    const token = this.tokenService.getAccessToken();
    if (!token) {
      this.ngZone.run(() => {
        alert('请先登录');
        this.authService.logout();
      });
      return false;
    }
    // 检查token是否过期
    if (this.tokenService.isTokenExpired()) {
      this.ngZone.run(() => {
        alert('登录已过期，正在重新登录...');
        // 尝试刷新token
        this.tokenService.refreshToken().subscribe({
          next: () => {
            // token刷新成功，可以继续上传
          },
          error: () => {
            alert('登录已过期，请重新登录');
            this.authService.logout();
          }
        });
      });
      return false;
    }
    return true;
  }
  // 多文件上传方法
  uploadFiles(files, fileType, successMessage, errorMessage, callback) {
    if (!this.quote) return;
    // 在上传前验证token
    if (!this.validateTokenBeforeUpload()) {
      return;
    }
    this.uploading = true;
    this.uploadProgress = 0;
    const formData = new FormData();
    files.forEach(file => {
      formData.append('files', file);
    });
    // 添加文件类型信息，告知后端这些文件应该存储在哪个数组中
    formData.append('fileType', fileType);
    // 创建带进度的HTTP请求
    const xhr = new XMLHttpRequest();
    // 监听上传进度
    xhr.upload.addEventListener('progress', event => {
      if (event.lengthComputable) {
        this.uploadProgress = Math.round(event.loaded / event.total * 100);
      }
    });
    // 监听响应
    xhr.addEventListener('load', () => {
      this.ngZone.run(() => {
        this.uploading = false;
        this.uploadProgress = 0;
        if (xhr.status === 200) {
          try {
            const updatedQuote = JSON.parse(xhr.responseText);
            console.log('上传成功，更新后的询价单:', updatedQuote);
            console.log('供应商文件列表:', updatedQuote.supplierFiles);
            this.quote = updatedQuote;
            console.log('设置this.quote后的quoterFiles:', this.quote?.quoterFiles);
            // 清空对应的临时文件列表
            const user = this.authService.getCurrentUser();
            switch (user?.role) {
              case 'customer':
                this.tempCustomerFiles = [];
                break;
              case 'supplier':
                this.tempSupplierFiles = [];
                break;
              case 'quoter':
              case 'admin':
                this.tempQuoterFiles = [];
                break;
